@WebMvcTest(UserController.class)
class UserControllerTest {
    @Autowired private MockMvc mockMvc;
    @MockBean private UserService userService;

    @Test
    void postUser_validBody_returns201() throws Exception {
        var req = new CreateUserRequest("user@example.com", "password");
        var res = new UserResponse(1L, "user@example.com");
        when(userService.create(any())).thenReturn(res);

        mockMvc.perform(post("/api/v1/users")
            .contentType(APPLICATION_JSON)
            .content(objectMapper.writeValueAsString(req)))
            .andExpect(status().isCreated())
            .andExpect(jsonPath("$.id").value(1))
            .andExpect(jsonPath("$.email").value("user@example.com"));
    }
}

@ExtendWith(MockitoExtension.class)
class UserServiceTest {
    @InjectMocks private UserService service;
    @Mock private UserRepository repo;
    @Mock private PasswordEncoder encoder;

    @Test
    void create_validRequest_savesEncryptedPassword() {
        var req = new CreateUserRequest("user@example.com", "secret123");
        when(encoder.encode("secret123")).thenReturn("$2a$10$...");
        when(repo.save(any())).thenAnswer(i -> {
            var u = (User) i.getArgument(0);
            u.setId(1L);
            return u;
        });

        var res = service.create(req);

        assertThat(res.id()).isEqualTo(1L);
        verify(encoder).encode("secret123");
        verify(repo).save(argThat(u -> u.getEmail().equals("user@example.com")));
    }
}

@Test
void findById_whenUserNotFound_throwsResourceNotFoundException() {
    // Arrange
    when(repo.findById(999L)).thenReturn(Optional.empty());

    // Act & Assert
    assertThatThrownBy(() -> service.findById(999L))
        .isInstanceOf(ResourceNotFoundException.class)
        .hasMessage("User 999 not found");
}
